CREATE TYPE "ScanStatus" AS ENUM ('queued','running','succeeded','partial','failed','cancelled');
CREATE TYPE "OpportunityStatus" AS ENUM ('discovered','watching','validating','sample_ordered','testing','validated','scaling','paused','rejected','discontinued');
CREATE TABLE "Advertiser" ("id" TEXT PRIMARY KEY,"workspaceId" TEXT NOT NULL REFERENCES "Workspace"("id") ON DELETE CASCADE,"source" TEXT NOT NULL,"externalId" TEXT,"name" TEXT NOT NULL,"pageUrl" TEXT,"isWatched" BOOLEAN NOT NULL DEFAULT false,"tags" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[],"notes" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE UNIQUE INDEX "Advertiser_workspaceId_source_name_key" ON "Advertiser"("workspaceId","source","name"); CREATE INDEX "Advertiser_workspaceId_isWatched_idx" ON "Advertiser"("workspaceId","isWatched");
CREATE TABLE "CompetitorAd" ("id" TEXT PRIMARY KEY,"workspaceId" TEXT NOT NULL REFERENCES "Workspace"("id") ON DELETE CASCADE,"advertiserId" TEXT NOT NULL REFERENCES "Advertiser"("id") ON DELETE CASCADE,"source" TEXT NOT NULL,"sourceAdId" TEXT,"canonicalKey" TEXT NOT NULL,"contentFingerprint" TEXT NOT NULL,"body" TEXT NOT NULL,"headline" TEXT,"cta" TEXT,"landingPageUrl" TEXT,"startedRunningAt" TIMESTAMP(3),"isWatched" BOOLEAN NOT NULL DEFAULT false,"tags" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[],"notes" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE UNIQUE INDEX "CompetitorAd_workspaceId_canonicalKey_key" ON "CompetitorAd"("workspaceId","canonicalKey"); CREATE INDEX "CompetitorAd_workspaceId_sourceAdId_idx" ON "CompetitorAd"("workspaceId","sourceAdId"); CREATE INDEX "CompetitorAd_workspaceId_contentFingerprint_idx" ON "CompetitorAd"("workspaceId","contentFingerprint");
CREATE TABLE "AdScan" ("id" TEXT PRIMARY KEY,"workspaceId" TEXT NOT NULL REFERENCES "Workspace"("id") ON DELETE CASCADE,"keyword" TEXT NOT NULL,"method" TEXT NOT NULL,"status" "ScanStatus" NOT NULL DEFAULT 'queued',"resultCount" INTEGER NOT NULL DEFAULT 0,"errorCode" TEXT,"errorMessage" TEXT,"startedAt" TIMESTAMP(3),"finishedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "AdScan_workspaceId_createdAt_idx" ON "AdScan"("workspaceId","createdAt");
CREATE TABLE "AdObservation" ("id" TEXT PRIMARY KEY,"scanId" TEXT NOT NULL REFERENCES "AdScan"("id") ON DELETE CASCADE,"competitorAdId" TEXT NOT NULL REFERENCES "CompetitorAd"("id") ON DELETE CASCADE,"observedAt" TIMESTAMP(3) NOT NULL,"isActive" BOOLEAN,"platforms" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[],"duplicateCount" INTEGER,"raw" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX "AdObservation_scanId_competitorAdId_key" ON "AdObservation"("scanId","competitorAdId"); CREATE INDEX "AdObservation_competitorAdId_observedAt_idx" ON "AdObservation"("competitorAdId","observedAt");
CREATE TABLE "Opportunity" ("id" TEXT PRIMARY KEY,"workspaceId" TEXT NOT NULL REFERENCES "Workspace"("id") ON DELETE CASCADE,"name" TEXT NOT NULL,"status" "OpportunityStatus" NOT NULL DEFAULT 'discovered',"score" INTEGER NOT NULL,"confidence" INTEGER NOT NULL,"scoreVersion" TEXT NOT NULL DEFAULT 'phase2-v1',"assumptions" TEXT,"risks" TEXT,"nextAction" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL); CREATE INDEX "Opportunity_workspaceId_status_idx" ON "Opportunity"("workspaceId","status");
CREATE TABLE "OpportunityEvidence" ("id" TEXT PRIMARY KEY,"opportunityId" TEXT NOT NULL REFERENCES "Opportunity"("id") ON DELETE CASCADE,"competitorAdId" TEXT NOT NULL REFERENCES "CompetitorAd"("id") ON DELETE RESTRICT,"reason" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP); CREATE UNIQUE INDEX "OpportunityEvidence_opportunityId_competitorAdId_key" ON "OpportunityEvidence"("opportunityId","competitorAdId");
CREATE TABLE "DecisionLog" ("id" TEXT PRIMARY KEY,"opportunityId" TEXT NOT NULL REFERENCES "Opportunity"("id") ON DELETE CASCADE,"fromStatus" "OpportunityStatus","toStatus" "OpportunityStatus" NOT NULL,"reason" TEXT NOT NULL,"actorId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP); CREATE INDEX "DecisionLog_opportunityId_createdAt_idx" ON "DecisionLog"("opportunityId","createdAt");